const webhook = $('Kill Business Webhook').first().json;
const businessId = webhook.body.businessId;
const businessName = webhook.body.businessName;
const killReason = webhook.body.reason;

// Safely read content from each GitHub node (may have failed)
function safeContent(nodeName) {
  try {
    const item = $(nodeName).first();
    if (item && item.json && item.json.content) {
      return Buffer.from(item.json.content, 'base64').toString('utf8');
    }
  } catch (e) {}
  return '[Not available]';
}

const stateContent = safeContent('Read State');
const stateSha = (() => { try { return $('Read State').first().json.sha || ''; } catch(e) { return ''; } })();
const strategyContent = safeContent('Read Strategy');
const weeklyPlanContent = safeContent('Read Weekly Plan');
const contentStrategyContent = safeContent('Read Content Strategy');
const supportLogContent = safeContent('Read Support Log');

const now = new Date().toISOString();

const prompt = `You are the CEO Agent for The Forge, an autonomous AI business operating system. A business is being killed and you must generate a comprehensive, structured post-mortem.

BUSINESS BEING KILLED:
- Business ID: ${businessId}
- Business Name: ${businessName}
- Kill Reason: ${killReason}
- Kill Timestamp: ${now}

BUSINESS STATE:
${stateContent}

BUSINESS STRATEGY:
${strategyContent}

WEEKLY PLAN:
${weeklyPlanContent}

CONTENT STRATEGY:
${contentStrategyContent}

SUPPORT LOG:
${supportLogContent}

Generate a structured post-mortem as a JSON object with ALL of the following fields from the Knowledge Graph post-mortem schema (Part IV Section 4.2 of the Operating Bible). Every field is required. If data is unavailable, provide your best estimate based on the context and note it as estimated.

Required JSON fields:
- business_id (string): The business ID
- business_type (string enum): One of smb_vertical_tool, consumer_app, b2b_saas, marketplace, content_platform, api_service, browser_extension
- niche (string): The specific niche/vertical
- launch_date (string ISO date): When the business launched
- death_date (string ISO date): Today
- lifetime_days (integer): Days from launch to death
- peak_mrr (number): Peak monthly recurring revenue achieved
- peak_users (integer): Peak number of users
- total_capital_deployed (number): Total capital spent
- total_revenue_recovered (number): Total revenue earned
- top_performing_assets (array of objects): Each with type, title, traffic, signups. Best performing content/marketing assets
- worst_performing_assets (array of objects): Each with type, views, signups, analysis. Worst performing assets with analysis of why
- cac_trajectory (array of objects): Each with week (integer) and cac (number or null). Weekly CAC progression
- cause_of_death (string): Detailed narrative of why the business died
- what_agent_would_do_differently (string): Detailed retrospective on what should have been done differently
- suggested_adjacent_opportunities (array of strings): Related business ideas that might work based on learnings
- general_notes (string): Comprehensive unstructured narrative. Write EVERYTHING you would want a future CEO Agent to know. What surprised you, what you learned that doesn't fit other fields, patterns you noticed, intuitions about adjacent opportunities. Length is not a concern - write everything.
- killed_at (string ISO timestamp): The kill timestamp

Respond with ONLY the JSON object, no markdown fencing, no explanation. The JSON must be valid and parseable.`;

return [{
  json: {
    businessId,
    businessName,
    killReason,
    killedAt: now,
    stateSha,
    prompt
  }
}];

const llmOutput = $('CEO Post-Mortem LLM Chain').first().json.text || $('CEO Post-Mortem LLM Chain').first().json.response;
const webhookData = $('Build Post-Mortem Prompt').first().json;

// Parse the LLM JSON output
let postMortem;
try {
  // Strip any markdown fencing if present
  let cleaned = llmOutput.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
  }
  postMortem = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse post-mortem JSON from LLM: ' + e.message + '\nRaw output: ' + llmOutput.substring(0, 500));
}

// Build the markdown post-mortem for GitHub
const md = `# Post-Mortem: ${webhookData.businessName}

**Business ID:** ${postMortem.business_id}
**Business Type:** ${postMortem.business_type}
**Niche:** ${postMortem.niche}
**Launch Date:** ${postMortem.launch_date}
**Death Date:** ${postMortem.death_date}
**Lifetime:** ${postMortem.lifetime_days} days
**Killed At:** ${postMortem.killed_at}

## Financial Summary
- **Peak MRR:** $${postMortem.peak_mrr}
- **Peak Users:** ${postMortem.peak_users}
- **Total Capital Deployed:** $${postMortem.total_capital_deployed}
- **Total Revenue Recovered:** $${postMortem.total_revenue_recovered}

## Top Performing Assets
${postMortem.top_performing_assets.map(a => `- **${a.type}**: "${a.title}" - ${a.traffic} traffic, ${a.signups} signups`).join('\n')}

## Worst Performing Assets
${postMortem.worst_performing_assets.map(a => `- **${a.type}**: ${a.views} views, ${a.signups} signups - ${a.analysis}`).join('\n')}

## CAC Trajectory
${postMortem.cac_trajectory.map(c => `- Week ${c.week}: ${c.cac === null ? 'N/A' : '$' + c.cac}`).join('\n')}

## Cause of Death
${postMortem.cause_of_death}

## What We Would Do Differently
${postMortem.what_agent_would_do_differently}

## Suggested Adjacent Opportunities
${postMortem.suggested_adjacent_opportunities.map(o => `- ${o}`).join('\n')}

## General Notes
${postMortem.general_notes}
`;

// Build updated state.md
const killedStateContent = `# ${webhookData.businessName} - Current State\n\n## Status: KILLED\n## Kill Date: ${postMortem.death_date}\n## Kill Reason: ${webhookData.killReason}\n\nThis business has been terminated via Death Protocol.\nSee post-mortem.md for full analysis.\n`;

return [{
  json: {
    businessId: webhookData.businessId,
    businessName: webhookData.businessName,
    killedAt: webhookData.killedAt,
    stateSha: webhookData.stateSha,
    postMortem,
    postMortemMarkdown: md,
    killedStateContent
  }
}];
